function encode(s) {
    const n = s.length;
    for (let i = Math.floor(n / 2); i > 0; i--) {
        if (n % i === 0) {
            const reps = n / i;
            const sub = s.slice(0, i);
            let composed = "";
            for (let j = 0; j < reps; j++) {
                composed += sub;
            }
            if (s === composed) {
                return `${reps}[${sub}]`;
            }
        }
    }
    return s;
}
