String encode(String s) {
    int n = s.length();
    for (int i = n / 2; i > 0; i--) {
        if (n % i == 0) {
            int reps = n / i;
            String sub = s.substring(0, i);
            StringBuilder composed = new StringBuilder();
            for (int j = 0; j < reps; j++) {
                composed.append(sub);
            }
            if (s.equals(composed.toString())) {
                return reps + "[" + sub + "]";
            }
        }
    }
    return s;
}
```

